  ('diplomatic-ea72210e-moex-00474', 'diplomatic-ea72210e', 'diplomatic-ea72210e-moex-111-cf527099', 'sub-diplomatic-ea72210e-07', NULL, 'single_choice', '關於外國法之適用，下列何者錯誤？', '["外國法之內容應遵守我國之公序良俗", "除外國法適用之結果有背於我國公序良俗者外，仍適用該外國法", "法官對於外國法之適用是否有背我國公序良俗有裁量權", "所謂公共秩序係指我國之立國精神與基本國策的具體表現"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:21:41+00:00", "source_pdf_sha1": "e1a4d6d077aa", "answer_pdf_sha1": "daee9d1e682f", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "108", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際法(含國際公法與國際私法)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-法文組"}'::jsonb, NULL),
